from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
from werkzeug.security import generate_password_hash, check_password_hash
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['SECRET_KEY'] = 'secret_key_here'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(64), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(128))

@app.before_first_request
def create_tables():
    db.create_all()

# logging config
logging.basicConfig(filename='application.log', level=logging.INFO,
                    format='%(asctime)s [%(levelname)s] %(message)s')

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        logging.warning(f'Login attempt with empty credentials: {request.remote_addr}')
        return jsonify({'error': 'empty_credentials'}), 401
    
    user = User.query.filter_by(username=username).first()
    
    if user and check_password_hash(user.password, password):
        logging.info(f'Successful login for user {username} from IP address {request.remote_addr}')
        return jsonify({'success': True})
    else:
        logging.warning(f'Login attempt failed for user {username}: {request.remote_addr}')
        return jsonify({'error': 'invalid_credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)